// DPDA Transition Function Representation
// δ[state][input_symbol][stack_top] = (next_state, stack_action)

// For DPDA accepting {a^n b^n | n ≥ 1} by empty stack
TRANSITIONS = {
 (q0, 'a', 'Z0'): (q0, 'aZ0'), // Push first 'a'
 (q0, 'a', 'a'): (q0, 'aa'), // Push more 'a's
 (q0, 'b', 'a'): (q1, 'ε'), // Start popping
 (q1, 'b', 'a'): (q1, 'ε'), // Continue popping
 (q1, 'ε', 'Z0'): (q0, 'ε') // Accept (empty stack)
}

// Stack is a list, index 0 = bottom, -1 = top
